package scripts; import ("fmt"; "gorm.io/driver/postgres"; "gorm.io/gorm"; "github.com/google/uuid"); type User struct { ID uuid.UUID `gorm:"type:uuid;primaryKey"`; Name string }; func RunCheckUsers() { dsn := "host=192.168.31.254 user=phucraitek0539 password=090103Phuc database=solar_om port=2602 sslmode=disable TimeZone=Asia/Ho_Chi_Minh"; db, err := gorm.Open(postgres.Open(dsn), &gorm.Config{}); if err != nil { panic(err); }; var users []User; db.Find(&users); for _, u := range users { fmt.Printf("User: %s %s\n", u.ID.String(), u.Name); } }